class SecurityMiddleware:
    """
    WSGI middleware that adds security headers and performs
    pre-dispatch security checks.
    
    This middleware does NOT perform its own SOAPAction-based routing.
    Routing is left entirely to spyne's internal dispatch mechanism,
    which correctly matches SOAPAction to the SOAP body operation.
    """

    ALLOWED_SOAP_ACTIONS = {
        'urn:financial.services/getBalance',
        'urn:financial.services/transferFunds',
        'urn:financial.services/getAccountInfo',
        '"urn:financial.services/getBalance"',
        '"urn:financial.services/transferFunds"',
        '"urn:financial.services/getAccountInfo"',
    }

    def __init__(self, app):
        self.app = app

    def __call__(self, environ, start_response):
        # Check Content-Type
        content_type = environ.get('CONTENT_TYPE', '')
        if environ.get('REQUEST_METHOD') == 'POST':
            if 'text/xml' not in content_type and 'application/soap+xml' not in content_type:
                # Allow WSDL requests (GET) but require proper content type for POST
                status = '415 Unsupported Media Type'
                response_headers = [('Content-Type', 'text/plain')]
                start_response(status, response_headers)
                return [b'Content-Type must be text/xml or application/soap+xml']

            # Validate SOAPAction is in the allowed set (defense in depth).
            # This does NOT route; it only rejects unknown actions early.
            soap_action = environ.get('HTTP_SOAPACTION', '').strip()
            if soap_action and soap_action not in self.ALLOWED_SOAP_ACTIONS:
                logger.warning("Rejected unknown SOAPAction: %s from %s",
                               soap_action[:100], environ.get('REMOTE_ADDR', 'unknown'))
                status = '400 Bad Request'
                response_headers = [('Content-Type', 'text/plain')]
                start_response(status, response_headers)
                return [b'Invalid SOAPAction header']

            # Rate limiting placeholder - in production use a proper rate limiter
            # Log the request for audit
            logger.info("SOAP request from %s, SOAPAction: %s",
                        environ.get('REMOTE_ADDR', 'unknown'),
                        soap_action[:100] if soap_action else 'none')

        def secure_start_response(status, response_headers, exc_info=None):
            # Add security headers
            security_headers = [
                ('X-Content-Type-Options', 'nosniff'),
                ('X-Frame-Options', 'DENY'),
                ('Strict-Transport-Security', 'max-age=31536000; includeSubDomains'),
                ('Cache-Control', 'no-store, no-cache, must-revalidate'),
                ('Pragma', 'no-cache'),
                ('X-XSS-Protection', '1; mode=block'),
            ]
            response_headers.extend(security_headers)
            return start_response(status, response_headers, exc_info)

        return self.app(environ, secure_start_response)


